import React, { useState } from 'react';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Link, useNavigate } from 'react-router-dom';
import FormInput from '../components/FormInput';
import { useAuth } from '../context/AuthContext';
import '../styles/Auth.css';

const Login = () => {
  const [credentials, setCredentials] = useState({ username: '', password: '' });
  const [errors, setErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setCredentials({
      ...credentials,
      [name]: value
    });
    
    // Clear error when user starts typing
    if (errors[name]) {
      setErrors({
        ...errors,
        [name]: ''
      });
    }
  };

  const validateForm = () => {
    const newErrors = {};
    
    if (!credentials.username) {
      newErrors.username = 'Username is required';
    } else if (credentials.username.length < 3) {
      newErrors.username = 'Username must be at least 3 characters';
    }
    
    if (!credentials.password) {
      newErrors.password = 'Password is required';
    } else if (credentials.password.length < 8) {
      newErrors.password = 'Password must be at least 8 characters';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validateForm()) {
      return;
    }
    
    setIsSubmitting(true);
    
    try {
      // For demonstration/testing purposes
      if (credentials.username === 'admin' && credentials.password === 'password123') {
        // Simulate successful login
        login({ 
          role: 'STORE_MANAGER', 
          username: credentials.username 
        });
        navigate('/admin/dashboard', { replace: true });
      } else if (credentials.username === 'sales' && credentials.password === 'password123') {
        login({ 
          role: 'SALES_STAFF', 
          username: credentials.username 
        });
        navigate('/sales/pos', { replace: true });
      } else if (credentials.username === 'inventory' && credentials.password === 'password123') {
        login({ 
          role: 'INVENTORY_STAFF', 
          username: credentials.username 
        });
        navigate('/inventory/manage', { replace: true });
      } else {
        setErrors({ general: 'Invalid username or password' });
      }
      
      // In production, uncomment this code and remove the if/else above
      /*
      const response = await fetch('/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          username: credentials.username,
          password: credentials.password
        })
      });
      
      if (response.ok) {
        const data = await response.json();
        
        // Store JWT token
        localStorage.setItem('token', data.token);
        
        // Log in user
        login({
          role: data.role,
          username: credentials.username
        });
        
        // Redirect based on user role
        switch (data.role) {
          case 'STORE_MANAGER':
            navigate('/admin/dashboard', { replace: true });
            break;
          case 'SALES_STAFF':
            navigate('/sales/pos', { replace: true });
            break;
          case 'INVENTORY_STAFF':
            navigate('/inventory/manage', { replace: true });
            break;
          default:
            navigate('/dashboard', { replace: true });
        }
      } else {
        const errorData = await response.json();
        setErrors({ general: errorData.message || 'Login failed. Please try again.' });
      }
      */
    } catch (error) {
      console.error('Login error:', error);
      setErrors({ general: 'An unexpected error occurred. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <div className="logo-container">
          <h1>Mira Textile</h1>
        </div>
        <h2>Login</h2>
        <form onSubmit={handleSubmit} className="auth-form">
          <FormInput
            label="Username"
            type="text"
            name="username"
            placeholder="e.g., john_doe"
            value={credentials.username}
            onChange={handleChange}
            error={errors.username}
            required
          />
          <div style={{ position: 'relative', width: '100%' }}>
            <FormInput 
              label="Password"
              type={showPassword ? "text" : "password"}
              name="password"
              placeholder="Enter your password"
              value={credentials.password}
              onChange={handleChange}
              error={errors.password}
              required
            />
            <span 
              className="password-toggle"
              onClick={() => setShowPassword(!showPassword)}
            >
              {showPassword ? <FaEyeSlash /> : <FaEye />}
            </span>
          </div>

          <div className="auth-options">
            <div></div> {/* Empty div for spacing */}
            <Link to="/forgot-password" className="forgot-password">Forgot Password?</Link>
          </div>
          
          <button 
            type="submit" 
            className={`auth-button ${isSubmitting ? 'submitting' : ''}`}
            disabled={isSubmitting}
          >
            {isSubmitting ? 'Logging in...' : 'Login'}
          </button>
          
          {errors.general && <p className="error-message">{errors.general}</p>}
        </form>
      </div>
    </div>
  );
};

export default Login;
